import React, { useState } from "react";
import { useNavigate } from "react-router-dom";
import "./package.css";
import img1 from "../Assets/img5.jpg";
import img2 from "../Assets/tent1.jpg";
import imgD1 from "../Assets/g1.jpeg";
import Feature from "./Feature";

const Package = () => {
  const navigate = useNavigate();
  const [pop, setpop] = useState(null);

  const handleBookNowClick = (stayType) => {
    navigate("/package-details", { state: { stayType } });
  };

  const openpop = (type) => {
    setpop(type);
  };

  const closepop = () => {
    setpop(null);
  };

  return (
    <div className="app2">
      <h1 className="heading">Our Packages</h1>
      <div className="card-container">
        {/** Card Data Array */}
        {[{
          title: "Tent Stay",
          price: "₹1199",
          imgSrc: img2,
          type: "Tent"
        }, {
          title: "Glam Stay",
          price: "₹1999",
          imgSrc: img1,
          type: "Glam"
        }, {
          title: "Dome Stay",
          price: "₹2999",
          imgSrc: imgD1,
          type: "Dome"
        }].map(({title, price, imgSrc, type}) => (
          <div className="card" key={title}>
            <div className="card-image-container">
              <img src={imgSrc} alt={title} className="card-image" />
            </div>
            <div className="card-content">
              <h2 className="card-title">{title}</h2>
              <p className="card-price">Starting From {price} Per Person</p>
              <button className="add-to-cart" onClick={() => handleBookNowClick(title)}>
                BOOK NOW
              </button>
              <button className="see-features" onClick={() => openpop(type)}>
                See Features
              </button>
            </div>
          </div>
        ))}
      </div>

      {pop && (
        <div className="pop">
          <div className="pop-content">
            <button className="close-pop" onClick={closepop}>✖</button>
            <Feature stayType={pop} />
          </div>
        </div>
      )}
    </div>
  );
};

export default Package;
